const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
if (!body.carrier_id) return { json: { _empty: true, status: 400, error: 'carrier_id required' } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
const b = $('Extract').first().json.body;
// Whitelist fields safe to update from the frontend.
const payload = { updated_at: new Date().toISOString() };
['appointment_status','agent_code','contracted_lines','province_authorized','expected_commission_pct','contact_name','contact_email','contact_phone','appointment_applied_at','appointment_approved_at','appointment_effective_at','appointment_terminated_at','termination_reason','active','notes'].forEach(function (k) { if (b[k] !== undefined && b[k] !== '') payload[k] = b[k]; });
// Coerce numeric / boolean shapes.
if (payload.expected_commission_pct !== undefined) payload.expected_commission_pct = parseFloat(payload.expected_commission_pct);
if (payload.contracted_lines !== undefined && typeof payload.contracted_lines === 'string') {
  try { payload.contracted_lines = JSON.parse(payload.contracted_lines); }
  catch (e) { payload.contracted_lines = payload.contracted_lines.split(',').map(function(s){ return s.trim(); }).filter(Boolean); }
}
return { json: { _ok: true, carrier_id: b.carrier_id, payload: payload } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
if (!row) return { json: { ok: false, error: 'carrier not found' } };
return { json: { ok: true, carrier: row } };
